def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        factor = 1.0
        penalty = 0.0
        adjustment = 0.0
        prime_check = True
        for val in range(2, 15):
            if all(val % d != 0 for d in range(2, int(np.sqrt(val)) +1 )):
                factor *= 1.01
            else:
                factor *= 0.99
            mod_val = cap % val
            if mod_val == 0:
                penalty += np.log1p(val) * (1 + 0.1 * factor)
            elif mod_val < val // 2:
                penalty -= np.sqrt(mod_val) / (val + 0.5)
            else:
                penalty += np.sin(ratio * val) / (val + 1)
            if ratio < 0.1 * val:
                score += (val ** 2) * np.exp(-ratio * val) * factor
            else:
                score -= (ratio * val) ** 0.5 / (val + 2) * factor
            if val % 3 == 0:
                adjustment += np.tanh(score / (val + 1))
            else:
                adjustment -= np.arctan(score / (val + 1))
            if val == 10:
                for mult in range(1, 6):
                    remainder = cap - item * mult
                    if remainder > 0:
                        if remainder % mult == 0:
                            adjustment += np.cbrt(remainder) / (mult + 0.7)
                        else:
                            adjustment -= np.log1p(abs(remainder)) / (mult + 1.3)
                    else:
                        adjustment -= abs(remainder) * 0.15 * mult
        final_score = (score + penalty + adjustment) / (cap + 1)
        if final_score > 0:
            priority = -final_score * np.exp(-ratio) * factor
        else:
            priority = -final_score * (np.log1p(cap) + np.sqrt(item)) * factor
        if ratio > 1:
            priority *= 1.4
        elif 0.5 < ratio <= 1:
            priority *= 1.1
        elif ratio < 0.2:
            priority *= 0.7
        if cap % 7 == 0:
            priority += np.sin(cap / (item + 1)) * 0.5
        if int(item) % 2 == 0 and cap % 2 == 1:
            priority -= np.cos(item / (cap + 1)) * 0.3
        priorities[i] = priority
    return priorities
